	if err != nil {
		t.Fatalf("failed to get HEAD: %v", err)
	}

	commit1, err := repo.CommitObject(head.Hash())
	if err != nil {
		t.Fatalf("failed to get commit: %v", err)
	}

	checkpointID1, found := trailers.ParseCheckpoint(commit1.Message)
	if !found {
